function cleanHtml(str) {
  return str
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<head[\s\S]*?<\/head>/gi, "")
    .replace(/<footer[\s\S]*?<\/footer>/gi, "")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function decodeEntities(str) {
  return str
    .replace(/&#x9;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&nbsp;/g, " ")
    .trim();
}

// Expected values from Excel
const excelRows = items.filter(i => i.json["Expected"]);

// Gmail node output
const gmail = items.find(i => i.json.subject || i.json.from || i.json.textAsHtml || i.json.text)?.json || {};
const fromAddress = gmail.from?.value?.[0]?.address || "";
const replyToAddress = gmail.replyTo?.value?.[0]?.address || "";
const subjectLine = (gmail.subject || "").replace(/^TEST\s*\|\s*/i, "").trim();

// Extract HTML Content node output (preheader)
const preheaderItem = items.find(i => i.json.preheader)?.json || {};
const preheader = preheaderItem.preheader || "";

// Body Copy
let bodyCopy = "";
if (gmail.textAsHtml) {
  bodyCopy = cleanHtml(gmail.textAsHtml);
  bodyCopy = decodeEntities(bodyCopy);
} else if (gmail.text) {
  bodyCopy = decodeEntities(gmail.text.trim());
}

// Validation logic
const results = excelRows.map(row => {
  const expected = String(row.json["Expected"] || "");
  let actualValue = "";

  if (expected.includes("@")) {
    actualValue = fromAddress || replyToAddress;
  } else if (expected.toLowerCase().includes("subject")) {
    actualValue = subjectLine;
  } else if (expected.toLowerCase().includes("preheader")) {
    actualValue = preheader;
  } else {
    actualValue = bodyCopy;
  }

  const match = expected.trim() === String(actualValue).trim() ? "MATCH" : "MISMATCH";
  return { Expected: expected, Actual: actualValue, Result: match };
});

return results.map(r => ({ json: r }));

