=// Parameters provided by user in node config
const sheetId = this.getNodeParameter("sheetId", 0) || "YOUR_SPREADSHEET_ID";
const sheetName = this.getNodeParameter("sheetName", 0) || "Sheet1";

const { google } = require("googleapis");
const sheets = google.sheets({ version: "v4", auth });

const response = await sheets.spreadsheets.values.get({
  spreadsheetId: sheetId,
  range: sheetName,
});

return response.data.values.map(row => ({ json: { row } }));

